import{_ as a,a as t,o as l,af as o}from"./chunks/framework.B3WftNMK.js";const p=JSON.parse('{"title":"常见问题集","description":"","frontmatter":{},"headers":[{"level":2,"title":"1. 无法加入服务器","slug":"_1-无法加入服务器","link":"#_1-无法加入服务器","children":[]},{"level":2,"title":"2. 登录后变为新账号，或与原账号信息不匹配","slug":"_2-登录后变为新账号-或与原账号信息不匹配","link":"#_2-登录后变为新账号-或与原账号信息不匹配","children":[]},{"level":2,"title":"3. 在低版本客户端中，有些东西看起来和高版本不一样，或者发生了变化，让它们看起来很陌生","slug":"_3-在低版本客户端中-有些东西看起来和高版本不一样-或者发生了变化-让它们看起来很陌生","link":"#_3-在低版本客户端中-有些东西看起来和高版本不一样-或者发生了变化-让它们看起来很陌生","children":[]}],"relativePath":"guide/q&a.md","filePath":"guide/q&a.md"}'),r={name:"guide/q&a.md"};function i(d,e,n,_,c,s){return l(),t("div",null,e[0]||(e[0]=[o('<h1 id="常见问题集" tabindex="-1">常见问题集 <a class="header-anchor" href="#常见问题集" aria-label="Permalink to &quot;常见问题集&quot;">​</a></h1><h2 id="_1-无法加入服务器" tabindex="-1">1. 无法加入服务器 <a class="header-anchor" href="#_1-无法加入服务器" aria-label="Permalink to &quot;1. 无法加入服务器&quot;">​</a></h2><p>这通常是多种原因导致的，例如 Mojang 正版验证服务无法连接、客户端版本不受支持等。</p><p>根据具体情况，我们才能确定问题原因。</p><h2 id="_2-登录后变为新账号-或与原账号信息不匹配" tabindex="-1">2. 登录后变为新账号，或与原账号信息不匹配 <a class="header-anchor" href="#_2-登录后变为新账号-或与原账号信息不匹配" aria-label="Permalink to &quot;2. 登录后变为新账号，或与原账号信息不匹配&quot;">​</a></h2><p>您可能不小心在启动器中登录了错误的用户名，或者您的用户名具有不同的 UUID 导致。如果是这样，请在您的启动器中登录正确的账号，或者检查 UUID 是否发生变化。</p><p>您也可能意外被服务器判定为了离线玩家，这种情况下，请执行 <code>/prem</code> 命令，这将会让服务器将您登记为正版玩家。如果您不具备正版账户，请绝不要执行这个命令，这会让您永久丢失访问权限，除非您联系管理员，否则这问题将不会得到解决。</p><h2 id="_3-在低版本客户端中-有些东西看起来和高版本不一样-或者发生了变化-让它们看起来很陌生" tabindex="-1">3. 在低版本客户端中，有些东西看起来和高版本不一样，或者发生了变化，让它们看起来很陌生 <a class="header-anchor" href="#_3-在低版本客户端中-有些东西看起来和高版本不一样-或者发生了变化-让它们看起来很陌生" aria-label="Permalink to &quot;3. 在低版本客户端中，有些东西看起来和高版本不一样，或者发生了变化，让它们看起来很陌生&quot;">​</a></h2><p>这种情况完全是因为您使用了低版本客户端。在理想情况下，您应当使用和服务器一致的版本，或者至少使用更高的版本。如果您是低版本玩家，那么 <code>Y≤0</code> 的地方是您无法访问的（低于 <code>1.17</code>）。我们理解您的选择，也为低版本提供了额外支持（使用木棍点击方块，或者是将准星对准方块执行 <code>/wt</code> 命令）。</p>',9)]))}const u=a(r,[["render",i]]);export{p as __pageData,u as default};
